import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter your name: ");
            String userName = reader.readLine();

            // Sanitize and escape user input before using it in HTML output
            String sanitizedUserName = Encode.forHtml(userName);

            System.out.println("Hello, " + sanitizedUserName + "!");

            // User input is now properly sanitized and escaped
            System.out.println("<p>Welcome, " + sanitizedUserName + "!</p>");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
